  "steps": [
    {
      "description": "Convert the Date columns in both datasets to Date class (if they aren't already).",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>% mutate(Date = as.Date(Date))\nspx_daily_5y <- spx_daily_5y %>% mutate(Date = as.Date(Date))",
      "considerations": "If Date is already Date, this is a harmless re‑cast. Ensures the join works on matching types.",
      "status": "pending"
    },
    {
      "description": "Calculate Bitcoin 30‑day log return and store it as `btc_ret_30d`.",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>% arrange(Date) %>% mutate(btc_ret_30d = (Close / lag(Close, 30)) - 1)",
      "considerations": "Uses simple arithmetic return; change to log return if preferred. The first 30 rows will be NA.",
      "status": "pending"
    },
    {
      "description": "Calculate S&P 500 30‑day return and store it as `spx_ret_30d`.",
      "r_code": "spx_daily_5y <- spx_daily_5y %>% arrange(Date) %>% mutate(spx_ret_30d = (Close / lag(Close, 30)) - 1)",
      "considerations": "Same logic as Bitcoin; first 30 rows become NA.",
      "status": "pending"
    },
    {
      "description": "Create a one‑day lag of the S&P 500 30‑day return (yesterday’s SPX return) and name it `spx_ret_30d_lag1`.",
      "r_code": "spx_daily_5y <- spx_daily_5y %>% mutate(spx_ret_30d_lag1 = lag(spx_ret_30d, 1))",
      "considerations": "Ensures we only use information available prior to the Bitcoin observation date.",
      "status": "pending"
    },
    {
      "description": "Select only the columns needed for the regression from each dataset.",
      "r_code": "btc_subset <- bitcoin_daily_5y %>% select(Date, btc_ret_30d)\nspx_subset <- spx_daily_5y %>% select(Date, spx_ret_30d_lag1)",
      "considerations": "Keeps the join tidy and avoids duplicate column names.",
      "status": "pending"
    },
    {
      "description": "Join the two subsets on Date, keeping only rows where both returns are present.",
      "r_code": "reg_data <- btc_subset %>% inner_join(spx_subset, by = \"Date\") %>% drop_na()",
      "considerations": "`inner_join` drops dates where either return is NA (e.g., the first 31 rows). Verify row count after join if needed.",
      "status": "pending"
    },
    {
      "description": "Run the linear regression of Bitcoin 30‑day return on lagged SPX 30‑day return and store the model as `btc_spx_reg`.",
      "r_code": "btc_spx_reg <- lm(btc_ret_30d ~ spx_ret_30d_lag1, data = reg_data)",
      "considerations": "The model object contains coefficients, summary, etc. Use `summary(btc_spx_reg)` to inspect.",
      "status": "pending"
    },
    {
      "description": "Clean up temporary objects that are no longer needed.",
      "r_code": "rm(btc_subset, spx_subset, reg_data)",
      "considerations": "Keeps the workspace tidy; the final objects `bitcoin_daily_5y`, `spx_daily_5y`, and `btc_spx_reg` remain.",
      "status": "pending"
    }
  ]
}

